// Ambil semua item hasil merge
const results = items.map(item => item.json);

// Helper functions
function SMA(data, period) {
  return data.map((_, i, arr) => {
    if (i < period) return null;
    const slice = arr.slice(i - period, i);
    return slice.reduce((a, b) => a + b, 0) / period;
  });
}

function RSI(data, period = 14) {
  const gains = [], losses = [];
  for (let i = 1; i < data.length; i++) {
    const diff = data[i] - data[i - 1];
    gains.push(diff > 0 ? diff : 0);
    losses.push(diff < 0 ? -diff : 0);
  }
  if (gains.length < period) return null;
  let avgGain = gains.slice(0, period).reduce((a,b)=>a+b,0)/period;
  let avgLoss = losses.slice(0, period).reduce((a,b)=>a+b,0)/period;
  for (let i = period; i < gains.length; i++) {
    avgGain = (avgGain * (period - 1) + gains[i]) / period;
    avgLoss = (avgLoss * (period - 1) + losses[i]) / period;
  }
  const rs = avgGain / (avgLoss || 1);
  return 100 - 100 / (1 + rs);
}

const output = [];

for (const data of results) {
  try {
    // result adalah chart.result[0] jika ada
    const result = data.chart?.result?.[0];

    // > SKIP jika tidak ada chart/result
    if (!result) {
      output.push({ json: { error: 'No chart/result for one item', raw: data } });
      continue;
    }

    // Symbol seharusnya ada di result.meta.symbol (Yahoo)
    const symbol = result.meta?.symbol || data.symbol || data.meta?.symbol || 'UNKNOWN';

    // Dapatkan closes, safety checks
    const closesRaw = result.indicators?.quote?.[0]?.close;
    if (!closesRaw || !Array.isArray(closesRaw)) {
      output.push({ json: { symbol, error: 'No close prices in response' } });
      continue;
    }
    const closes = closesRaw.filter(v => v !== null && v !== undefined);

    // Pastikan cukup data untuk MA200; kalau tidak, beri flag
    if (closes.length < 50) {
      output.push({ json: { symbol, error: 'Not enough candles', candles: closes.length } });
      continue;
    }

    // Hitung indikator
    const ma50 = SMA(closes, 50);
    const ma200 = SMA(closes, 200);
    const lastClose = closes.at(-1);
    const lastMA50 = ma50.filter(v => v !== null).at(-1) || null;
    const lastMA200 = ma200.filter(v => v !== null).at(-1) || null;
    const rsi = RSI(closes, 14);

    // Tentukan sinyal (prioritas RSI dulu)
    let signal = '⚪ Tidak ada sinyal saat ini';
    if (rsi !== null && rsi < 30) signal = '🔵 RSI Oversold (Potensi Buy)';
    else if (rsi !== null && rsi > 70) signal = '🔴 RSI Overbought (Potensi Sell)';
    else if (lastMA50 !== null && lastMA200 !== null && lastMA50 > lastMA200) signal = '🟢 Golden Cross (Buy Signal)';
    else if (lastMA50 !== null && lastMA200 !== null && lastMA50 < lastMA200) signal = '🔻 Death Cross (Sell Signal)';

    output.push({
      json: {
        symbol,
        lastClose,
        rsi: rsi !== null ? Number(rsi.toFixed(2)) : null,
        ma50: lastMA50 !== null ? Number(lastMA50.toFixed(2)) : null,
        ma200: lastMA200 !== null ? Number(lastMA200.toFixed(2)) : null,
        signal
      }
    });
  } catch (err) {
    output.push({ json: { error: err.message } });
  }
}

return output;

