const data = items[0].json.chart?.result?.[0];
if (!data) {
  return [{ json: { error: "❌ Tidak ada data dari Yahoo Finance." } }];
}

const closes = data.indicators.quote[0].close.filter(v => v !== null);

// === Fungsi bantu ===
function SMA(data, period) {
  return data.map((_, i, arr) => {
    if (i < period) return null;
    const slice = arr.slice(i - period, i);
    return slice.reduce((a, b) => a + b, 0) / period;
  });
}

function RSI(data, period = 14) {
  let gains = [], losses = [];
  for (let i = 1; i < data.length; i++) {
    const diff = data[i] - data[i - 1];
    gains.push(diff > 0 ? diff : 0);
    losses.push(diff < 0 ? -diff : 0);
  }

  if (gains.length < period) return null;

  let avgGain = gains.slice(0, period).reduce((a, b) => a + b, 0) / period;
  let avgLoss = losses.slice(0, period).reduce((a, b) => a + b, 0) / period;

  for (let i = period; i < gains.length; i++) {
    avgGain = (avgGain * (period - 1) + gains[i]) / period;
    avgLoss = (avgLoss * (period - 1) + losses[i]) / period;
  }

  const rs = avgGain / (avgLoss || 1);
  return 100 - 100 / (1 + rs);
}

// === Hitung indikator ===
const ma50 = SMA(closes, 50);
const ma200 = SMA(closes, 200);

const lastClose = closes.at(-1);
const lastMA50 = ma50.at(-1);
const lastMA200 = ma200.filter(v => v !== null).at(-1) || lastMA50;
const rsi = RSI(closes, 14);

// === Tentukan sinyal ===
let signal = "⚪ Tidak ada sinyal saat ini";
if (rsi && rsi < 30) signal = "🔵 RSI Oversold (Potensi Buy)";
else if (rsi && rsi > 70) signal = "🔴 RSI Overbought (Potensi Sell)";
else if (lastMA50 > lastMA200) signal = "🟢 Golden Cross (Buy Signal)";
else if (lastMA50 < lastMA200) signal = "🔻 Death Cross (Sell Signal)";

// === Return hasil ===
return [{
  json: {
    symbol: data.meta.symbol || "BTC-USD",
    lastClose,
    rsi: rsi ? rsi.toFixed(2) : null,
    ma50: lastMA50 ? lastMA50.toFixed(2) : null,
    ma200: lastMA200 ? lastMA200.toFixed(2) : null,
    signal
  }
}];

